import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { CalendarIcon, Mail } from 'lucide-react';
import axios from 'axios';

export default function AddAccessContent() {
    const navigate = useNavigate();
    const [formData, setFormData] = useState({
        login: '',
        firstName: '',
        lastName: '',
        email: '',
        platform: '',
        action: '',
        ticket: '',
        date: '',
        file: null,
    });

    const handleChange = (e) => {
        const { name, value, type, files } = e.target;
        if (type === 'file') {
            setFormData((prev) => ({ ...prev, file: files[0] }));
        } else {
            setFormData((prev) => ({ ...prev, [name]: value }));
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();

        try {
            const payload = {
                login: formData.login,
                name: `${formData.firstName} ${formData.lastName}`,
                mail: formData.email,
                action: formData.action, // doit correspondre à une valeur de ton ActionEnum
                num_ticket: formData.ticket,
                plateforme_id: parseInt(formData.platformId), // champ à ajouter au formulaire
                utilisateur_id: 1//userIdFromTokenOrContext // à récupérer depuis l'auth ou props
            };

            await axios.post('http://localhost:5000/acces', payload);

            navigate('/access');
        } catch (err) {
            console.error('Erreur lors de la création de l’accès :', err);
        }
    };
    const [plateformes, setPlateformes] = useState([]);
    // eslint-disable-next-line no-unused-vars
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchPlateformes = async () => {
            try {
                const res = await axios.get('http://localhost:5000/plateformes');
                setPlateformes(res.data);
                setLoading(false);
            } catch (error) {
                console.error('Erreur de chargement des plateformes :', error);
                setLoading(false);
            }
        };
        fetchPlateformes();
    }, []);



    return (
        <div className="flex flex-col p-6 gap-8">
            <div>
                <h1 className="text-2xl font-bold text-gray-800">Ajouter un accès</h1>
            </div>

            {/* Form Container */}
            <form onSubmit={handleSubmit} className="flex-1 max-w-3xl bg-white rounded-lg shadow-md p-8">
                <h2 className="text-xl font-semibold mb-6">Add Access</h2>

                <div className="grid grid-cols-2 gap-4">
                    <div>
                        <label className="block text-sm mb-1">Login</label>
                        <input
                            type="text"
                            name="login"
                            value={formData.login}
                            onChange={handleChange}
                            placeholder="Login"
                            className="w-full border rounded px-3 py-2"
                            required
                        />
                    </div>
                    <div>
                        <label className="block text-sm mb-1">First name</label>
                        <input
                            type="text"
                            name="firstName"
                            value={formData.firstName}
                            onChange={handleChange}
                            placeholder="First name"
                            className="w-full border rounded px-3 py-2"
                            required
                        />
                    </div>
                    <div>
                        <label className="block text-sm mb-1">Last name</label>
                        <input
                            type="text"
                            name="lastName"
                            value={formData.lastName}
                            onChange={handleChange}
                            placeholder="Last name"
                            className="w-full border rounded px-3 py-2"
                            required
                        />
                    </div>
                    <div className="col-span-2">
                        <label className="block text-sm mb-1">Email</label>
                        <div className="relative">
                            <span className="absolute left-3 top-2.5 text-gray-500">
                                <Mail size={16} />
                            </span>
                            <input
                                type="email"
                                name="email"
                                value={formData.email}
                                onChange={handleChange}
                                placeholder="example@domain.com"
                                className="w-full border rounded pl-10 px-3 py-2"
                                required
                            />
                        </div>
                    </div>
                </div>

                <div className="mt-6">
                    <label className="block text-sm mb-1">Platform</label>
                    <select
                        value={formData.platformId}
                        onChange={(e) => setFormData({ ...formData, platformId: e.target.value })}
                        className="w-full border rounded px-3 py-2"
                        required
                    >
                        <option value="">-- Choisir une plateforme --</option>
                        {plateformes.map((p) => (
                            <option key={p.id} value={p.id}>
                                {p.nom}
                            </option>
                        ))}
                    </select>
                </div>

                <div className="mt-6">
                    <label className="block text-sm mb-2">Action</label>
                    <div className="flex gap-4">
                        {['Creation', 'Update', 'Suspension', 'Deletion'].map((action) => (
                            <label key={action} className="flex items-center gap-2">
                                <input
                                    type="radio"
                                    name="action"
                                    value={action.toLowerCase()}
                                    checked={formData.action === action.toLowerCase()}
                                    onChange={handleChange}
                                />
                                {action}
                            </label>
                        ))}
                    </div>
                </div>

                <div className="mt-6 grid grid-cols-2 gap-4">
                    <div>
                        <label className="block text-sm mb-1">Ticket</label>
                        <input
                            type="text"
                            name="ticket"
                            value={formData.ticket}
                            onChange={handleChange}
                            placeholder="N° Ticket"
                            className="w-full border rounded px-3 py-2"
                            required
                        />
                    </div>
                    <div>
                        <label className="block text-sm mb-1">Date</label>
                        <div className="relative">
                            <span className="absolute left-3 top-2.5 text-gray-500">
                                <CalendarIcon size={16} />
                            </span>
                            <input
                                type="date"
                                name="date"
                                value={formData.date}
                                onChange={handleChange}
                                className="w-full border rounded pl-10 px-3 py-2"
                                required
                            />
                        </div>
                    </div>
                </div>

                <div className="flex gap-4 justify-end mt-8">
                    <button
                        type="button"
                        onClick={() => navigate('/access')}
                        className="px-4 py-2 border rounded bg-gray-100 hover:bg-gray-200"
                    >
                        Go back
                    </button>
                    <button
                        type="submit"
                        className="px-4 py-2 rounded bg-blue-800 text-white hover:bg-blue-700"
                    >
                        Add
                    </button>
                </div>
            </form>

            {/* File Upload Panel */}
            <div className="w-80 bg-white shadow-md rounded-lg p-6 h-fit">
                <div className="flex justify-between items-center mb-4">
                    <h3 className="text-lg font-semibold">Upload files</h3>
                    <button className="text-gray-500 hover:text-gray-700">&times;</button>
                </div>
                <div className="border-2 border-dashed border-gray-300 rounded-md p-6 text-center">
                    <p className="text-sm text-gray-500">Drop files here</p>
                    <p className="text-xs text-gray-400">Supported format: PDF, DOCX</p>
                    <div className="mt-4">
                        <input
                            type="file"
                            name="file"
                            onChange={handleChange}
                            className="hidden"
                            id="file-upload"
                            accept=".pdf,.doc,.docx"
                        />
                        <label htmlFor="file-upload" className="text-blue-700 underline cursor-pointer text-sm">
                            Browse files
                        </label>
                    </div>
                </div>
                <div className="flex justify-between mt-6">
                    <button className="px-4 py-2 rounded bg-gray-200 hover:bg-gray-300">Cancel</button>
                    <button className="px-4 py-2 rounded bg-blue-800 text-white hover:bg-blue-700">Upload</button>
                </div>
            </div>
        </div>
    );
}
